int* twoSum(int* numbers, int n, int target, int* retSize) {
    int lo = 0, hi = n - 1;
    while (lo < hi) {
        int s = numbers[lo] + numbers[hi];
        if (s == target) {
            int* ans = malloc(2 * sizeof(int));
            ans[0] = lo + 1; ans[1] = hi + 1; *retSize = 2; return ans;
        }
        if (s < target) lo++; else hi--;
    }
    *retSize = 0; return NULL;
}
